Author: David Yastremsky <dyastremsky@nvidia.com>
Date:   Tue Feb 21 07:59:08 2023 -0800

    (TRITON) Remove random selection fallback when signature def not found - TF1
---
 triton/tensorflow_backend_tf.cc | 25 +++++++++++++++----------
 1 file changed, 15 insertions(+), 10 deletions(-)

diff --git a/triton/tensorflow_backend_tf.cc b/triton/tensorflow_backend_tf.cc
index 7d0df07f8d..b939b06e44 100644
--- a/triton/tensorflow_backend_tf.cc
+++ b/triton/tensorflow_backend_tf.cc
@@ -1,4 +1,4 @@
-// Copyright (c) 2019-2022, NVIDIA CORPORATION. All rights reserved.
+// Copyright (c) 2019-2023, NVIDIA CORPORATION. All rights reserved.
 //
 // Redistribution and use in source and binary forms, with or without
 // modification, are permitted provided that the following conditions
@@ -990,18 +990,23 @@ TRITONTF_ModelCreateFromSavedModel(
   auto sig_itr =
       bundle->meta_graph_def.signature_def().find(SIGNATURE_DEF_KEY_TO_USE);
   if (sig_itr == bundle->meta_graph_def.signature_def().end()) {
-    // If default serving signature_def key is not found, maybe it is named
-    // something else, use one that is neither init_op key nor train_op key
-    for (sig_itr = bundle->meta_graph_def.signature_def().begin();
+    // If serving signature_def key is not specified and default is not found,
+    // maybe it is named something else. Use one that is neither init_op key
+    // nor train_op key
+    if(strcmp(signature_def, "") == 0){
+      for (sig_itr = bundle->meta_graph_def.signature_def().begin();
          sig_itr != bundle->meta_graph_def.signature_def().end(); sig_itr++) {
-      if ((sig_itr->first != INIT_OP_SIGNATURE_DEF_KEY) &&
-          (sig_itr->first != TRAIN_OP_SIGNATURE_DEF_KEY)) {
-        LOG(WARNING) << "unable to find serving signature '"
-                     << SIGNATURE_DEF_KEY_TO_USE;
-        LOG(WARNING) << "using signature '" << sig_itr->first << "'";
-        break;
+        if ((sig_itr->first != INIT_OP_SIGNATURE_DEF_KEY) &&
+            (sig_itr->first != TRAIN_OP_SIGNATURE_DEF_KEY)) {
+          LOG(WARNING) << "unable to find serving signature '"
+                      << SIGNATURE_DEF_KEY_TO_USE;
+          LOG(WARNING) << "using signature '" << sig_itr->first << "'";
+          break;
+        }
       }
     }
+    
+    // If serving signature_def key is not found, return error
     if (sig_itr == bundle->meta_graph_def.signature_def().end()) {
       return TRITONTF_ErrorNew(
           "unable to load model '" + std::string(model_name) + "', expected '" +

commit 8a04c11d0538e18b02c7b29d7fca4f1756a36cff
Author: Nathan Luehr <nluehr@nvidia.com>
Date:   Thu Nov 17 10:39:36 2022 -0800

    Update some cuGraph APIs for CUDA 12
---
 tensorflow/stream_executor/cuda/cuda_driver.cc | 14 ++++++++++++++
 1 file changed, 14 insertions(+)

diff --git a/tensorflow/stream_executor/cuda/cuda_driver.cc b/tensorflow/stream_executor/cuda/cuda_driver.cc
index 994be40c8c..d245ad7169 100644
--- a/tensorflow/stream_executor/cuda/cuda_driver.cc
+++ b/tensorflow/stream_executor/cuda/cuda_driver.cc
@@ -1594,6 +1594,14 @@ static port::StatusOr<T> GetSimpleAttribute(CUdevice device,
     GpuContext* context, CUgraph graph, CUgraphExec* graph_exec) {
 #if CUDA_VERSION >= 10000
   ScopedActivateContext activated{context};
+#if CUDA_VERSION >= 12000
+  CUresult res = cuGraphInstantiate(graph_exec, graph, 0LL);
+  if (res != CUDA_SUCCESS) {
+    LOG(ERROR) << "could not instantiate executable graph for context "
+               << context->context() << ": " << ToString(res);
+    return false;
+  }
+#else
   char log_buffer[1024];
   CUresult res = cuGraphInstantiate(graph_exec, graph,
                                     /* error_node = */ nullptr, log_buffer,
@@ -1604,6 +1612,7 @@ static port::StatusOr<T> GetSimpleAttribute(CUdevice device,
                << log_buffer;
     return false;
   }
+#endif

   VLOG(1) << "successfully instantiated executable graph for context "
           << context->context() << " on thread";
@@ -1620,9 +1629,14 @@ static port::StatusOr<T> GetSimpleAttribute(CUdevice device,
                                                    CUgraph graph) {
 #if CUDA_VERSION >= 10020
   ScopedActivateContext activated{context};
+#if CUDA_VERSION >= 12000
+  CUgraphExecUpdateResultInfo result_info;
+  CUresult res = cuGraphExecUpdate(graph_exec, graph, &result_info);
+#else
   CUresult res = cuGraphExecUpdate(graph_exec, graph,
                                    /* error_node = */ nullptr,
                                    /* update_result = */ nullptr);
+#endif
   if (res != CUDA_SUCCESS) {
     // VLOG because updating a graph is often done optimistically before falling
     // back to instantiating a new graph, so an ERROR is not appropriate.

