+                   << in.resource_handle_val(i).ShortDebugString()
+                   << "\", returned status: " << s.ToString();
+        buf->Unref();
+        return nullptr;
+      }
+    }
+    for (int64 i = in_n; i < n; ++i) {
+      data[i] = ResourceHandle();
