new file mode 100644
index 0000000000..b4a75e29cb
--- /dev/null
+++ b/tensorflow/compiler/xla/tests/buffer_donation_test.cc
@@ -0,0 +1,229 @@
+/* Copyright 2020 The TensorFlow Authors. All Rights Reserved.
+
